    @Test
    @DisplayName("RemovingVisitor on a parent with two children skips tail of removed and continues traversal to next sibling")
    public void test_TC11() {
        // GIVEN: parent with two leaf children
        Element parent = new Element("div");
        Element c1 = new Element("a");
        Element c2 = new Element("b");
